package main

import (
	"fmt"
	"github.com/spf13/cobra"
)

func main() {
	// Test 1: CommandPath with Experimental
	cmd := &cobra.Command{
		Use: "test",
		Experimental: true,
	}

	// Create parent and subcommand to test inheritance
	parent := &cobra.Command{
		Use: "parent",
	}
	parent.AddCommand(cmd)

	path := cmd.CommandPath()
	fmt.Printf("CommandPath (should have prefix): %s\n", path)

	// Test 2: UseLine with Experimental
	useline := cmd.UseLine()
	fmt.Printf("UseLine (should have prefix): %s\n", useline)

	// Test 3: Non-experimental command
	normalCmd := &cobra.Command{
		Use: "normal",
	}
	normalCmd.SetParent(parent)

	normalPath := normalCmd.CommandPath()
	fmt.Printf("Normal CommandPath (should NOT have prefix): %s\n", normalPath)

	normalUseline := normalCmd.UseLine()
	fmt.Printf("Normal UseLine (should NOT have prefix): %s\n", normalUseline)
}
EOF
